/**
 * @summary Validasi key dari script eksternal (tanpa login)
 */
export const getPublicCheckKeyUrl = (params: PublicCheckKeyParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/public/check?${stringifiedParams}`
    : `/api/public/check`;
};

export const publicCheckKey = async (
  params: PublicCheckKeyParams,
  options?: RequestInit,
): Promise<PublicCheckResponse> => {
  return customFetch<PublicCheckResponse>(getPublicCheckKeyUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getPublicCheckKeyQueryKey = (params?: PublicCheckKeyParams) => {
  return [`/api/public/check`, ...(params ? [params] : [])] as const;
};

